@Test
public void testGetCountsSingleDimension() {
    final MultidimensionalCounter c = new MultidimensionalCounter(5);
    for (int i = 0; i < 5; i++) {
        final int[] indices = c.getCounts(i);
        Assert.assertEquals(1, indices.length);
        Assert.assertEquals(i, indices[0]);
    }
}

@Test
public void testGetCountsFirstAndLastIndex() {
    final MultidimensionalCounter c = new MultidimensionalCounter(3, 4, 5);
    int[] indices = c.getCounts(0);
    Assert.assertArrayEquals(new int[]{0, 0, 0}, indices);

    indices = c.getCounts(59);
    Assert.assertArrayEquals(new int[]{2, 3, 4}, indices);
}

@Test
public void testGetCountsBoundaryTransitions() {
    final MultidimensionalCounter c = new MultidimensionalCounter(2, 3);

    int[] indices = c.getCounts(2);
    Assert.assertArrayEquals(new int[]{0, 2}, indices);

    indices = c.getCounts(3);
    Assert.assertArrayEquals(new int[]{1, 0}, indices);

    indices = c.getCounts(4);
    Assert.assertArrayEquals(new int[]{1, 1}, indices);
}
